class DataProtector:
    """Handles encryption/hashing of sensitive data before storage."""

    def __init__(self, encryption_key: str, hmac_secret: str):
        if not encryption_key or not hmac_secret:
            raise ValueError(
                "ENCRYPTION_KEY and HMAC_SECRET must be set via environment variables. "
                "Never hardcode secrets."
            )
        self._encryption_key = encryption_key.encode('utf-8')
        self._hmac_secret = hmac_secret.encode('utf-8')

    def compute_hmac(self, data: str) -> str:
        """Compute HMAC for data integrity verification."""
        return hmac.new(self._hmac_secret, data.encode('utf-8'), hashlib.sha256).hexdigest()

    def hash_token(self, token: str) -> str:
        """One-way hash for tokens - we store the hash, not the token itself."""
        return hashlib.sha256(
            (token + self._encryption_key.decode('utf-8')).encode('utf-8')
        ).hexdigest()

    def prepare_for_storage(self, data: dict) -> str:
        """Serialize data and add integrity check."""
        serialized = json.dumps(data, sort_keys=True)
        integrity_hash = self.compute_hmac(serialized)
        envelope = {
            "data": data,
            "integrity": integrity_hash,
            "stored_at": datetime.utcnow().isoformat()
        }
        return json.dumps(envelope)

    def retrieve_from_storage(self, raw: str) -> Optional[dict]:
        """Deserialize and verify integrity."""
        try:
            envelope = json.loads(raw)
            serialized = json.dumps(envelope["data"], sort_keys=True)
            expected_hash = self.compute_hmac(serialized)
            if not hmac.compare_digest(expected_hash, envelope["integrity"]):
                logger.warning("Data integrity check failed!")
                return None
            return envelope["data"]
        except (json.JSONDecodeError, KeyError) as e:
            logger.error(f"Failed to retrieve data from storage: {e}")
            return None


class RedisClusterClient:
    """Manages connection to Redis cluster with retry logic and health checks."""

    def __init__(self):
        self._client: Optional[RedisCluster] = None
        self._protector: Optional[DataProtector] = None
        self._initialize()

    def _initialize(self):
        """Initialize Redis cluster connection and data protector."""
        self._protector = DataProtector(ENCRYPTION_KEY, HMAC_SECRET)
        self._connect()

    def _parse_nodes(self):
        """Parse Redis node addresses from configuration."""
        nodes = []
        for node_str in REDIS_NODES.split(","):
            node_str = node_str.strip()
            if ":" in node_str:
                host, port = node_str.rsplit(":", 1)
                nodes.append(ClusterNode(host=host, port=int(port)))
            else:
                nodes.append(ClusterNode(host=node_str, port=6379))
        return nodes

    def _connect(self):
        """Establish connection to Redis cluster."""
        nodes = self._parse_nodes()
        try:
            self._client = RedisCluster(
                startup_nodes=nodes,
                password=REDIS_PASSWORD if REDIS_PASSWORD else None,
                ssl=REDIS_SSL,
                ssl_cert_reqs="required" if REDIS_SSL else None,
                socket_timeout=REDIS_SOCKET_TIMEOUT,
                socket_connect_timeout=REDIS_SOCKET_TIMEOUT,
                retry_on_timeout=REDIS_RETRY_ON_TIMEOUT,
                max_connections=REDIS_MAX_CONNECTIONS,
                decode_responses=True,
                skip_full_coverage_check=True,
            )
            # Verify connection
            self._client.ping()
            logger.info("Successfully connected to Redis cluster")
        except Exception as e:
            logger.error(f"Failed to connect to Redis cluster: {e}")
            raise

    def _execute_with_retry(self, operation, max_retries=3, backoff_factor=0.5):
        """Execute a Redis operation with retry logic."""
        last_exception = None
        for attempt in range(max_retries):
            try:
                return operation()
            except (ConnectionError, TimeoutError) as e:
                last_exception = e
                wait_time = backoff_factor * (2 ** attempt)
                logger.warning(
                    f"Redis operation failed (attempt {attempt + 1}/{max_retries}): {e}. "
                    f"Retrying in {wait_time}s..."
                )
                time.sleep(wait_time)
                try:
                    self._connect()
                except Exception:
                    pass
            except RedisError as e:
                logger.error(f"Redis error: {e}")
                raise
        logger.error(f"All retry attempts exhausted. Last error: {last_exception}")
        raise last_exception

    @property
    def client(self) -> RedisCluster:
        return self._client

    @property
    def protector(self) -> DataProtector:
        return self._protector

    def health_check(self) -> dict:
        """Check Redis cluster health."""
        try:
            start = time.time()
            self._client.ping()
            latency = (time.time() - start) * 1000
            cluster_info = self._client.cluster_info()
            return {
                "status": "healthy",
                "latency_ms": round(latency, 2),
                "cluster_state": cluster_info.get("cluster_state", "unknown"),
                "cluster_slots_assigned": cluster_info.get("cluster_slots_assigned", 0),
                "cluster_known_nodes": cluster_info.get("cluster_known_nodes", 0),
            }
        except Exception as e:
            return {"status": "unhealthy", "error": str(e)}

